// ========================================
// 🔐 V7-27次元防衛: JITトークン検証 + HMAC署名検証
// ========================================

const headers = $input.first().json.headers || {};
const body = $input.first().json.body || $input.first().json;

// JITトークン検証
const jitToken = headers['x-n3-jit-token'] || headers['X-N3-JIT-Token'];
const tokenExpiry = headers['x-n3-token-expiry'] || headers['X-N3-Token-Expiry'];

if (jitToken && tokenExpiry) {
  const expiryTs = parseInt(tokenExpiry, 10);
  const now = Math.floor(Date.now() / 1000);

  if (now > expiryTs) {
    return [{ json: { error: true, message: 'JITトークン期限切れ', code: 'JIT_TOKEN_EXPIRED' } }];
  }

  const apiUrl = $env.N3_API_URL || 'http://localhost:3000';
  try {
    const verifyResponse = await fetch(`${apiUrl}/api/n8n-auth/verify-jit-token`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ token: jitToken, expiry: tokenExpiry })
    });
    const verifyResult = await verifyResponse.json();
    if (!verifyResult.valid) {
      return [{ json: { error: true, message: 'JITトークン無効', code: 'INVALID_JIT_TOKEN' } }];
    }
  } catch (e) {
    console.log('JITトークン検証エラー: ' + e.message);
  }
}

// HMAC署名検証
const signature = headers['x-n3-signature'] || headers['X-N3-Signature'] || '';
const timestamp = headers['x-n3-timestamp'] || headers['X-N3-Timestamp'] || '';

if (signature && timestamp) {
  const secret = $env.N3_HMAC_SECRET;
  if (!secret) {
    return [{ json: { error: true, message: 'N3_HMAC_SECRET未設定', code: 'CONFIG_ERROR' } }];
  }

  const ts = parseInt(timestamp, 10);
  const now = Math.floor(Date.now() / 1000);
  if (Math.abs(now - ts) > 300) {
    return [{ json: { error: true, message: 'タイムスタンプ期限切れ', code: 'TIMESTAMP_EXPIRED' } }];
  }

  try {
    const verifyUrl = $env.PRICING_ENGINE_URL || 'http://localhost:8000';
    const response = await fetch(`${verifyUrl}/verify-signature`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ payload: JSON.stringify(body), signature, timestamp })
    });
    const result = await response.json();
    if (!result.valid) {
      return [{ json: { error: true, message: '署名検証失敗', code: 'INVALID_SIGNATURE' } }];
    }
  } catch (e) {
    console.log('署名検証スキップ: ' + e.message);
  }
}

return [{ json: { ...body, _auth_verified: true } }];

// ========================================
// 🔥 燃焼上限チェック
// ========================================

const body = $input.first().json;
const userId = body.user_id || 'default';

const dailyLimit = parseInt($env.BURN_LIMIT_DAILY || '1000', 10);
const apiUrl = $env.N3_API_URL || 'http://localhost:3000';

try {
  const usageResponse = await fetch(`${apiUrl}/api/cost-tracking/check-limit`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ user_id: userId, operation: 'error_recovery', estimated_cost: 0.10, daily_limit: dailyLimit })
  });

  const usageResult = await usageResponse.json();

  if (usageResult.limit_exceeded) {
    return [{ json: { error: true, message: `燃焼上限超過`, code: 'BURN_LIMIT_EXCEEDED' } }];
  }

  return [{ json: { ...body, _burn_limit_checked: true } }];
} catch (e) {
  return [{ json: { ...body, _burn_limit_checked: false } }];
}

// ========================================
// 💰 V7-特化: 修復価値判定 (ROI Check)
// 「直す価値があるか」を最初に判定
// ========================================

const body = $input.first().json;
const productId = body.product_id;
const userId = body.user_id || 'default';

if (body.error) {
  return [{ json: body }];
}

const apiUrl = $env.N3_API_URL || 'http://localhost:3000';

try {
  // 商品の期待利益を取得
  const profitResponse = await fetch(`${apiUrl}/api/products/${productId}/expected-profit`, {
    method: 'GET',
    headers: { 'Content-Type': 'application/json' }
  });

  const profitResult = await profitResponse.json();

  // 修復コスト vs 期待利益を計算
  const repairCost = 0.15; // AI呼び出しコスト（USD）
  const expectedProfit = profitResult.expected_profit_usd || 0;
  const repairROI = expectedProfit > 0 ? (expectedProfit - repairCost) / repairCost : -1;

  // 修復価値判定閾値
  const minROI = parseFloat($env.REPAIR_MIN_ROI || '0.5');

  if (repairROI < minROI) {
    return [{ json: { 
      ...body, 
      should_repair: false, 
      route_to_exit_strategy: true,
      repair_roi: repairROI,
      expected_profit: expectedProfit,
      repair_cost: repairCost,
      reason: `修復ROI(${repairROI.toFixed(2)})が閾値(${minROI})未満`
    } }];
  }

  return [{ json: { 
    ...body, 
    should_repair: true, 
    repair_roi: repairROI,
    expected_profit: expectedProfit 
  } }];
} catch (e) {
  // 判定失敗時は修復を試みる
  return [{ json: { ...body, should_repair: true, roi_check_error: e.message } }];
}

// V7: 入力検証（認証済みデータ）
const body = $input.first().json;

if (body.error) {
  return [{ json: body }];
}

const apiUrl = $env.N3_API_URL;
const secret = $env.N8N_INTERNAL_SECRET;
if (!apiUrl) return [{ json: { error: true, message: 'N3_API_URL未設定', code: 'CONFIG_ERROR' } }];
if (!secret) return [{ json: { error: true, message: 'N8N_INTERNAL_SECRET未設定', code: 'CONFIG_ERROR' } }];

const productId = body.product_id;
const marketplace = body.marketplace || 'ebay_us';
const limit = body.limit || 10;
const force = body.force || false;
const userId = body.user_id || 'default';

return [{ json: { 
  product_id: productId, 
  marketplace: marketplace, 
  user_id: userId,
  limit: limit,
  force: force,
  should_repair: body.should_repair,
  repair_roi: body.repair_roi,
  request_timestamp: new Date().toISOString()
} }];

const errors = $node['エラー商品取得'].json;
const errorArr = Array.isArray(errors) ? errors : [errors];
const dictArr = Array.isArray($input.first().json) ? $input.first().json : [$input.first().json];
const errorDict = dictArr.reduce((acc, e) => { if (e.error_code) acc[e.error_code] = e; return acc; }, {});

return errorArr.filter(p => p.id).map(p => {
  const info = errorDict[p.error_code] || { error_category: 'unknown', auto_recoverable: false, recovery_strategy: 'Manual review' };
  return { json: {
    user_id: p.user_id, product_id: p.id, sku: p.sku, updated_at: p.updated_at,
    title: p.english_title || p.title, category_id: p.ebay_category_id, condition: p.condition,
    price_usd: p.ddp_price_usd || p.price_usd, listing_data: p.listing_data, ebay_account: p.ebay_account,
    error_code: p.error_code, error_message: p.error_message, error_category: info.error_category,
    auto_recoverable: info.auto_recoverable, recovery_strategy: info.recovery_strategy,
    retry_count_24h: p.retry_count_24h || 0
  } };
});

let ai = { diagnosis: 'Parse error', corrections: {}, confidence: 0.5, reasoning: '' };
try {
  const text = $node['Gemini: エラー診断'].json.text || $node['Gemini: エラー診断'].json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) ai = JSON.parse(jsonMatch[0]);
} catch (e) { ai.reasoning = 'AI応答パース失敗'; }

const prev = $node['1件ずつ処理'].json;
const confidence = ai.confidence || 0.5;

if (confidence < 0.6) {
  return [{ json: { ...prev, success: false, action: 'needs_review', reason: '信頼度低(' + Math.round(confidence*100) + '%)' } }];
}

let listingData = {};
try { listingData = typeof prev.listing_data === 'string' ? JSON.parse(prev.listing_data || '{}') : (prev.listing_data || {}); } catch (e) {}

const itemSpecifics = listingData.item_specifics || {};
for (const [key, value] of Object.entries(ai.corrections || {})) {
  if (value && typeof value === 'string') itemSpecifics[key] = value;
}
if (!itemSpecifics.MPN && prev.error_category === 'item_specifics') itemSpecifics.MPN = 'Does Not Apply';
if (!itemSpecifics.Brand && prev.error_category === 'item_specifics') itemSpecifics.Brand = 'Unbranded';
listingData.item_specifics = itemSpecifics;

return [{ json: { ...prev, success: true, action: 'data_corrected', ai_diagnosis: ai, updated_listing_data: listingData, corrections: ai.corrections || {}, confidence } }];

const results = $input.all().map(i => i.json);
const recovered = results.filter(r => r.action === 'data_corrected').length;
const needsReview = results.filter(r => r.action === 'needs_review').length;
const notRecoverable = results.filter(r => r.action === 'not_auto_recoverable').length;

return [{ json: {
  success: true,
  summary: { total: results.length, recovered, needs_review: needsReview, not_recoverable: notRecoverable },
  details: results.slice(0, 10).map(r => ({ sku: r.sku, action: r.action, conf: r.confidence })),
  ts: new Date().toISOString(),
  v7_features: ['roi_check', 'exit_strategy', 'ai_decision_trace']
} }];
